const input = $input.first().json;
const action = input.action || 'list_libraries';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

// Fetch seafile_url
const urlCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.seafile&cred_key=eq.seafile_url&select=cred_value',
  headers: pgHeaders
});
if (!urlCreds || urlCreds.length === 0 || !urlCreds[0].cred_value) {
  return [{ json: { error: 'Seafile URL not configured. Use add_credential to set it up.' } }];
}

// Fetch seafile_token
const tokenCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.seafile&cred_key=eq.seafile_token&select=cred_value',
  headers: pgHeaders
});
if (!tokenCreds || tokenCreds.length === 0 || !tokenCreds[0].cred_value) {
  return [{ json: { error: 'Seafile API token not configured. Use add_credential to set it up.' } }];
}

const baseUrl = urlCreds[0].cred_value.replace(/\/+$/, '');
const token = tokenCreds[0].cred_value;
const sfHeaders = {
  'Authorization': 'Bearer ' + token,
  'Accept': 'application/json'
};

function formatSize(bytes) {
  if (bytes >= 1073741824) return (bytes / 1073741824).toFixed(1) + ' GB';
  if (bytes >= 1048576) return (bytes / 1048576).toFixed(1) + ' MB';
  if (bytes >= 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return bytes + ' B';
}

// === list_libraries ===
if (action === 'list_libraries') {
  const type = input.type || '';
  try {
    let url = baseUrl + '/api2/repos/';
    if (type) url += '?type=' + encodeURIComponent(type);
    const data = await helpers.httpRequest({ method: 'GET', url, headers: sfHeaders });
    if (!data || data.length === 0) {
      return [{ json: { result: 'No libraries found.' } }];
    }
    let result = 'Seafile Libraries (' + data.length + '):\n\n';
    for (const lib of data) {
      result += '**' + lib.name + '** (ID: ' + lib.id + ')\n';
      result += '  Size: ' + formatSize(lib.size) + ' | Type: ' + (lib.type || 'repo') + '\n';
      if (lib.owner) result += '  Owner: ' + lib.owner + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list libraries: ' + err.message } }];
  }

// === list_directory ===
} else if (action === 'list_directory') {
  const repoId = input.repo_id;
  if (!repoId) return [{ json: { error: 'Parameter "repo_id" is required.' } }];
  const path = input.path || '/';
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api2/repos/' + encodeURIComponent(repoId) + '/dir/?p=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    if (!data || data.length === 0) {
      return [{ json: { result: 'Directory "' + path + '" is empty.' } }];
    }
    let result = 'Contents of ' + path + ' (' + data.length + ' items):\n\n';
    for (const item of data) {
      const icon = item.type === 'dir' ? '[dir]  ' : '[file] ';
      result += icon + item.name;
      if (item.size) result += ' (' + formatSize(item.size) + ')';
      if (item.modifier_name) result += ' — modified by ' + item.modifier_name;
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list directory: ' + err.message } }];
  }

// === get_file_detail ===
} else if (action === 'get_file_detail') {
  const repoId = input.repo_id;
  const path = input.path;
  if (!repoId || !path) return [{ json: { error: 'Parameters "repo_id" and "path" are required.' } }];
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api2/repos/' + encodeURIComponent(repoId) + '/file/detail/?p=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    let result = '**' + data.name + '**\n';
    result += 'Path: ' + path + '\n';
    if (data.size !== undefined) result += 'Size: ' + formatSize(data.size) + '\n';
    if (data.last_modifier_name) result += 'Last modified by: ' + data.last_modifier_name + '\n';
    if (data.last_modified) result += 'Last modified: ' + new Date(data.last_modified * 1000).toISOString().split('T')[0] + '\n';
    if (data.id) result += 'File ID: ' + data.id + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get file detail: ' + err.message } }];
  }

// === download_file ===
} else if (action === 'download_file') {
  const repoId = input.repo_id;
  const path = input.path;
  if (!repoId || !path) return [{ json: { error: 'Parameters "repo_id" and "path" are required.' } }];
  try {
    const downloadUrl = await helpers.httpRequest({
      method: 'GET',
      url: baseUrl + '/api2/repos/' + encodeURIComponent(repoId) + '/file/?p=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    const cleanUrl = String(downloadUrl).replace(/^"|"$/g, '');
    const textExts = ['.txt', '.md', '.json', '.csv', '.xml', '.yaml', '.yml', '.html', '.css', '.js', '.py', '.sh', '.log', '.ini', '.conf', '.cfg', '.toml', '.env', '.sql'];
    const ext = path.toLowerCase().substring(path.lastIndexOf('.'));
    if (textExts.includes(ext)) {
      try {
        const content = await helpers.httpRequest({ method: 'GET', url: cleanUrl, encoding: 'utf-8', returnFullResponse: false });
        const text = typeof content === 'string' ? content : JSON.stringify(content);
        if (text.length > 5000) {
          return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\nContent (truncated):\n' + text.substring(0, 5000) + '\n\n... (' + text.length + ' chars total)' } }];
        }
        return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\nContent:\n' + text } }];
      } catch (e) {
        // Fall through to returning just the URL
      }
    }
    return [{ json: { result: 'File: ' + path + '\nDownload URL: ' + cleanUrl + '\n\n(Binary file — use the download URL to access)' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get download link: ' + err.message } }];
  }

// === search_files ===
} else if (action === 'search_files') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  try {
    let url = baseUrl + '/api2/search/?q=' + encodeURIComponent(query);
    if (input.search_repo) url += '&search_repo=' + encodeURIComponent(input.search_repo);
    if (input.per_page) url += '&per_page=' + encodeURIComponent(input.per_page);
    const data = await helpers.httpRequest({ method: 'GET', url, headers: sfHeaders });
    if (!data.results || data.results.length === 0) {
      return [{ json: { result: 'No files found for "' + query + '".' } }];
    }
    let result = 'Search results for "' + query + '" (' + data.total + ' total):\n\n';
    for (const item of data.results) {
      result += '**' + item.name + '**\n';
      result += '  Library: ' + item.repo_name + ' | Path: ' + item.fullpath + '\n';
      if (item.size) result += '  Size: ' + formatSize(item.size) + '\n';
      if (item.content_highlight) result += '  ...' + item.content_highlight.replace(/<[^>]+>/g, '') + '...\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Search failed: ' + err.message } }];
  }

// === create_share_link ===
} else if (action === 'create_share_link') {
  const repoId = input.repo_id;
  const path = input.path;
  if (!repoId || !path) return [{ json: { error: 'Parameters "repo_id" and "path" are required.' } }];
  try {
    const body = { repo_id: repoId, path: path };
    if (input.password) body.password = input.password;
    if (input.expire_days) body.expire_days = parseInt(input.expire_days, 10);
    const data = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/api/v2.1/share-links/',
      headers: { ...sfHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    let result = 'Share link created:\n';
    result += 'URL: ' + data.link + '\n';
    result += 'Path: ' + path + '\n';
    if (data.expire_date) result += 'Expires: ' + data.expire_date + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create share link: ' + err.message } }];
  }

// === delete_file ===
} else if (action === 'delete_file') {
  const repoId = input.repo_id;
  const path = input.path;
  if (!repoId || !path) return [{ json: { error: 'Parameters "repo_id" and "path" are required.' } }];
  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: baseUrl + '/api2/repos/' + encodeURIComponent(repoId) + '/file/?p=' + encodeURIComponent(path),
      headers: sfHeaders
    });
    return [{ json: { result: 'Successfully deleted: ' + path } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete: ' + err.message } }];
  }

// === file_operation ===
} else if (action === 'file_operation') {
  const repoId = input.repo_id;
  const path = input.path;
  const operation = input.operation;
  if (!repoId || !path || !operation) return [{ json: { error: 'Parameters "repo_id", "path", and "operation" (rename|move|copy) are required.' } }];
  if (!['rename', 'move', 'copy'].includes(operation)) {
    return [{ json: { error: 'Invalid operation "' + operation + '". Must be rename, move, or copy.' } }];
  }
  try {
    let formBody = 'operation=' + encodeURIComponent(operation);
    if (operation === 'rename') {
      if (!input.newname) return [{ json: { error: 'Parameter "newname" is required for rename.' } }];
      formBody += '&newname=' + encodeURIComponent(input.newname);
    } else {
      if (!input.dst_repo || !input.dst_dir) return [{ json: { error: 'Parameters "dst_repo" and "dst_dir" are required for ' + operation + '.' } }];
      formBody += '&dst_repo=' + encodeURIComponent(input.dst_repo) + '&dst_dir=' + encodeURIComponent(input.dst_dir);
    }
    await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/api2/repos/' + encodeURIComponent(repoId) + '/file/?p=' + encodeURIComponent(path),
      headers: { ...sfHeaders, 'Content-Type': 'application/x-www-form-urlencoded' },
      body: formBody
    });
    if (operation === 'rename') {
      return [{ json: { result: 'Renamed "' + path + '" to "' + input.newname + '".' } }];
    } else {
      return [{ json: { result: operation.charAt(0).toUpperCase() + operation.slice(1) + 'd "' + path + '" to ' + input.dst_dir + ' in repo ' + input.dst_repo + '.' } }];
    }
  } catch (err) {
    return [{ json: { error: 'File operation failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_libraries, list_directory, get_file_detail, download_file, search_files, create_share_link, delete_file, file_operation.' } }];
}
